import configparser
import os

def serialize(config, path):
    with open(path, 'w') as f:
        for section in config.sections():
            f.write(f"[{section}]\n")
            for key, value in config[section].items():
                # Attempt to preserve case for keys that are all lowercase
                # by capitalizing the character at the index of the first uppercase letter in value.
                new_key = key
                if key.islower():
                    for i, c in enumerate(value):
                        if c.isupper():
                            if i < len(key):
                                new_key = key[:i] + c + key[i+1:]
                            else:
                                # If the uppercase letter is beyond the key length, keep as is
                                pass
                            break
                lines = value.splitlines()
                f.write(f"{new_key} = {lines[0]}\n")
                for line in lines[1:]:
                    f.write(f"{line}\n")
